import React from "react";


import PlaceList from "../components/PlaceList";

const DUMMY_PLACES = [
    {
        id: 'p1',
        title: 'Dubai – Stad van records en glitter',
        description: 'One of the most famous sky scrapers in the worls!',
        imageUrl: 'https://travelizi.nl/sites/default/files/inline-images/Atlantis%2C%20The%20Palm%2C%20Dubai-faisal-manga-4NeuZU-ynnw-unsplash.jpg',
        address: 'Midtown Manhattan, Fifth Avenue at 34th Street, New York City.',
        location: {
            lat: 40.7484405,
            lng: -73.9878584
        },
        creator: 'u1'
    },
    {
        id: 'p2',
        title: ' New York City (Statue of Liberty)',
        description: 'There are different geographical, cultural, financial, and political aspects to consider.',
        imageUrl: 'https://www.westernunion.com/blogs-staticassets/R25-07.05.0-161/media/Travel_Spotlight_USA_02.jpg',
        location: {
            lat: 40.6892494,
            lng: 74.0470753,
        },
        creator: 'u2'
    },

    {
        id: 'p3',
        title: ' Canda(Moraine Lake)',
        description: 'Moraine Lake is a snow and glacially fed alpine lake in Banff National Park, 14 kilometres outside the village of Lake Louise, Alberta, Canada. ',
        imageUrl: 'https://banfflakelouise.bynder.com/m/3d04f19979f432ec/2000x1080_jpg-2022_MoraineLake_TravelAlberta_RothandRamberg-3.jpg',
        location: {
            lat: 51.3215507,
            lng: -116.1952415,
        },
        creator: 'u2'
    },
]
    const UserPlaces = () => {
    return <PlaceList items= {DUMMY_PLACES} />;
};

export default UserPlaces;
